ruleContent.content:
ChapterContent
@js:
function U(e) {
    return e.split("").map( e => {
        return e.match(/[A-Za-z]/) ? (c = Math.floor(e.charCodeAt(0) / 97), k = (e.toLowerCase().charCodeAt(0) - 83) % 26 || 26, String.fromCharCode(k + (0 == c ? 64 : 96))) : e
   }).join("")
}
result && result.length > 10 ? java.base64Decoder(U(result)) : '这是 🔒 付费章节 哦！\n';

ruleSearch.bookList:
@js:
    var aladdin = JSON.parse(result).aladdin;
    var list= [];

    var bid = aladdin.bid;
    var html = String(java.ajax( 'https://t.shuqi.com/catalog/' + bid ) );
    var scpubKey = html.match(/bscpubKey":"(\w+)"/)[1];  
    var timestamp =~~(Date.now()/1e3);
    var userId = '8000000';
    var sign =  java.md5Encode(String(bid) + timestamp + userId + scpubKey); 
//java.md5Encode hex_md5 str_md5
    var params ='&bookId=' + bid + '&user_id=' + userId + '&timestamp=' + timestamp + '&sign=' + sign ;

    let e = { cata: 'http://content.shuqireader.com/openapi/book/chapterlist?shuqi_h5=205&platform=0'+ params };
    Object.assign(aladdin, e);

    list.push(aladdin);
    list;

