@js:
function base64(_str){
	var staticchars="PAhw7UT1B0a9kQDKZsjIASmOezxYG4CHo5Jyfg2b8FLpEvRr3WtVnlqMidu6oN";
	var encodechars="";
	for(var i=0;i<_str.length;i++){
		var num0=staticchars.indexOf(_str[i]);
