@js:
list=[]
names={}
bSrc=src
elements=java.getElement('class.play_body')
for(i=0;i<result.length&&i<elements.length;i++){
	  java.setContent(result[i])
	  snamepath='class.play_menu@text'
	  sname=String(java.getString(snamepath))
	         .replace('-------点击展开播放','')
	  java.setContent(elements[i])
	  element=java.getElement('class.play_body@dl@dt')
	  for(j=element.length-1;j>=0;j--){
	  	  java.setContent(element[j])
	  	  name=java.getString('tag.a@text')
	  	  href=java.getString('tag.a@href')
	  	  index=element.length-j-1
	  	  names[`[${sname}]${name}`]={
	  	  	  "i":String(i),
	  	  	  "j":String(index)
	  	  }
	  	  list.push({
	  	  	"name":`[${sname}]${name}`,
	  	  	"href":String(href)
	  	  })
	  }
}
source.setVariable(String(JSON.stringify(names)))
java.setContent(bSrc)
list

