function u(){
		try{
uID = JSON.parse(JSON.stringify(source.getLoginHeaderMap())).uid;
}
catch(e){ uID ="0";	}
time = Date.now();
if(!String(api_path).match(/pwdMdLogOn/)){u = String(api_path) + "&timestamp="+time+"&uID="+uID;}
else{u = String(api_path) + "&timestamp="+time;}
x = "XKrqBSeeEwgDy2pT";
if(String(api_path).match(/list\/commbook/)){
	sg = method + String(u+api_Params).replace(/\?|&/g,"") +x;
	}
	else{ sg = method + String(u).replace(/\?|&/g,"") + x;}
en = encodeURIComponent(sg);
sign = java.md5Encode(en);
url = u + api_Params +"&sign="+sign;
return url;
	}


//打印字符串
function log(t){
		if(t==undefined) return;
		java.toast(t);
	}

//放置登入头
function put(json){
		return source.putLoginHeader(
			JSON.stringify(json)
		);
	}

//登录设置
function login() {    	 	
   let pcd = result.手机号;
   let pwd = result.密码;
	 mdPwd = java.md5Encode(pwd);
  method = "GET";
  api_path ="http://a.lc1001.com/app/sso/pwdMdLogOn?consumerKey=LCREAD_ANDROID&mdPwd="+mdPwd+"&pcd="+pcd;
	api_Params = "";
   u();
   D = JSON.parse(java.ajax(url));

   head = {
	 	"uid": D.DATA.UID,
	 	"token": D.DATA.TOKEN
	 	}
	 	put(head)	
	 t =D.MSG;
	if(t =="SUCCESS"){
		t= D.DATA.STRRESULT+"："+D.DATA.MEMBER+"："+D.DATA.UNAME
		}
	else t=t;	

return log(t)
}

